                <span className="font-mono text-[7px] tracking-[0.2em] uppercase font-bold text-white">E2EE</span>
              </div>
              <div className="font-mono text-[9px] text-white/80 uppercase tracking-[0.3em] font-bold">
                {data.copyright}
              </div>
            </div>
          </div>
        </div>
      </div>
    </section>
  );
};

