import React, { useEffect, useRef, useState } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import Section from './components/Section';
import ContactSection from './components/ContactSection';
import ExpertiseSection from './components/ExpertiseSection';
import Layout from './components/Layout';
import { sections, type Language } from './constants/sections';

export default function LandingPage() {
  const [activeSection, setActiveSection] = useState(0);
  const [language, setLanguage] = useState<Language>('mk');
  const [hoveredNav, setHoveredNav] = useState<number | null>(null);
  const containerRef = useRef<HTMLDivElement>(null);
  const sectionRefs = useRef<(HTMLDivElement | null)[]>([]);

  const currentSections = sections[language];

  useEffect(() => {
    const observerOptions = {
      root: containerRef.current,
      threshold: 0.5,
    };

    const observerCallback = (entries: IntersectionObserverEntry[]) => {
      entries.forEach((entry) => {
        if (entry.isIntersecting) {
          const index = sectionRefs.current.findIndex((ref) => ref === entry.target);
          if (index !== -1) {
            setActiveSection(index);
          }
        }
      });
    };

    const observer = new IntersectionObserver(observerCallback, observerOptions);
    sectionRefs.current.forEach((ref) => { if (ref) observer.observe(ref); });

    return () => { 
      sectionRefs.current.forEach((ref) => { if (ref) observer.unobserve(ref); });
    };
  }, [language]);

  const handleNavClick = (index: number) => {
    const target = sectionRefs.current[index];
    if (target && containerRef.current) {
      containerRef.current.scrollTo({
        top: target.offsetTop,
        behavior: 'smooth'
      });
    }
  };

  const isAtTop = activeSection === 0;

  return (
    <Layout>
      <motion.header 
        initial={false}
        animate={{
          backgroundColor: isAtTop ? 'rgba(3, 3, 3, 0)' : 'rgba(3, 3, 3, 0.85)',
          backdropFilter: isAtTop ? 'blur(0px)' : 'blur(24px)',
          borderBottomColor: isAtTop ? 'rgba(255, 255, 255, 0)' : 'rgba(255, 255, 255, 0.05)',
        }}
        className="fixed top-0 left-0 right-0 z-50 px-6 py-3 md:px-16 md:py-4 flex justify-between items-center transition-all duration-700 border-b"
      >
        <div className="flex-1 flex justify-start">
          <motion.button
            whileHover={{ 
              scale: 1.05, 
              backgroundColor: 'rgba(255,255,255,0.08)',
              borderColor: '#3b82f6',
              boxShadow: '0 0 20px rgba(59,130,246,0.2)'
            }}
            whileTap={{ scale: 0.95 }}
            onClick={() => setLanguage(l => l === 'mk' ? 'en' : 'mk')}
            className="px-4 py-2 text-[10px] font-black uppercase tracking-[0.25em] text-white/70 border border-white/10 rounded-full hover:text-white transition-all font-mono"
          >
            {language === 'mk' ? 'EN' : 'MK'}
          </motion.button>
        </div>

        <motion.div 
          whileHover={{ scale: 0.95, opacity: 0.9 }}
          animate={{ scale: 0.9 }}
          initial={{ scale: 0.9 }}
          className="flex-none text-center cursor-pointer transition-opacity"
          onClick={() => handleNavClick(0)}
        >
          <span className="text-lg md:text-2xl font-heading font-black tracking-tighter text-white uppercase">
            M&M <span className="text-primary">Media</span>
          </span>
        </motion.div>

        <div className="flex-1 flex justify-end" />
      </motion.header>

      {/* Navigation Dots with Tooltips */}
      <div className="fixed right-6 md:right-12 top-1/2 -translate-y-1/2 flex flex-col gap-4 md:gap-8 z-50">
        {currentSections.map((section, index) => (
          <div key={index} className="relative flex items-center justify-end">
            <AnimatePresence>
              {hoveredNav === index && (
                <motion.span
                  initial={{ opacity: 0, x: -10 }}
                  animate={{ opacity: 1, x: -20 }}
                  exit={{ opacity: 0, x: -10 }}
                  className="absolute right-full mr-4 font-mono text-[9px] font-black tracking-[0.3em] text-primary uppercase whitespace-nowrap pointer-events-none"
                >
                  {section.title}
                </motion.span>
              )}
            </AnimatePresence>
            <button
              onClick={() => handleNavClick(index)}
              onMouseEnter={() => setHoveredNav(index)}
              onMouseLeave={() => setHoveredNav(null)}
              className="group relative flex items-center justify-center p-2"
            >
              <motion.div
                animate={{
                  scale: index === activeSection ? 1.8 : hoveredNav === index ? 1.4 : 1,
                  backgroundColor: index === activeSection ? '#3b82f6' : hoveredNav === index ? 'rgba(255,255,255,0.4)' : 'rgba(255,255,255,0.15)',
                  boxShadow: index === activeSection 
                    ? '0 0 20px rgba(59,130,246,0.6)' 
                    : hoveredNav === index 
                      ? '0 0 10px rgba(255,255,255,0.2)' 
                      : '0 0 0px transparent'
                }}
                className="w-1.5 h-1.5 rounded-full transition-all duration-300"
              />
            </button>
          </div>
        ))}
      </div>

      <div ref={containerRef} className="snap-container no-scrollbar">
        {currentSections.map((section, index) => (
          <div 
            key={`${section.id}-${language}`} 
            ref={(el) => { sectionRefs.current[index] = el; }}
            className="snap-child"
          >
            {section.id === 'contact' ? (
              <ContactSection isActive={index === activeSection} language={language} />
            ) : section.id === 'expertise' ? (
              <ExpertiseSection 
                isActive={index === activeSection} 
                language={language} 
              />
            ) : (
              <Section {...section} isActive={index === activeSection} />
            )}
          </div>
        ))}
      </div>
    </Layout>
  );
}

import React, { useState, useEffect, useRef, useMemo } from 'react';
