import React, { useState, useEffect, useRef, useMemo } from 'react';
import { motion, AnimatePresence, useScroll, useTransform } from 'framer-motion';
import { ArrowRight } from 'lucide-react';
import { SectionData } from '../constants/sections';
import { BrandingSeal } from './SharedUI';

interface SectionProps extends SectionData {
  isActive: boolean;
}

const TechBackground: React.FC = () => {
  const chars = useMemo(() => Array.from({ length: 10 }).map((_, i) => ({
    id: i, x: Math.random() * 100, y: Math.random() * 100,
    char: ['0', '1', '<', '>', '{', '/', '#'][Math.floor(Math.random() * 7)]
  })), []);

  return (
    <div className="absolute inset-0 z-[2] opacity-20 pointer-events-none">
      {chars.map((c) => (
        <motion.div
          key={c.id}
          animate={{ opacity: [0, 0.4, 0], y: [`${c.y}%`, `${c.y - 10}%`] }}
          transition={{ duration: 10 + c.id, repeat: Infinity, ease: "linear" }}
          className="absolute font-mono text-primary text-[10px] font-bold"
          style={{ left: `${c.x}%`, top: `${c.y}%` }}
        >
          {c.char}
        </motion.div>
      ))}
    </div>
  );
};

const Section: React.FC<SectionProps> = ({ 
  isActive, subtitle, title, content, showButton, buttonText, backgroundImage, id 
}) => {
  const [loaded, setLoaded] = useState(false);
  const sectionRef = useRef<HTMLElement>(null);
  const { scrollYProgress } = useScroll({ target: sectionRef, offset: ["start end", "end start"] });
  const bgY = useTransform(scrollYProgress, [0, 1], ["-10%", "10%"]);

  useEffect(() => {
    if (backgroundImage) {
      const img = new Image();
      img.src = backgroundImage;
      img.onload = () => setLoaded(true);
    } else setLoaded(true);
  }, [backgroundImage]);

  return (
    <section ref={sectionRef} className="relative h-[100dvh] w-full snap-child flex flex-col justify-center overflow-hidden bg-surface">
      <div className="absolute inset-0 z-0 overflow-hidden">
        <AnimatePresence>
          {backgroundImage && loaded && (
            <motion.div 
              initial={{ opacity: 0 }}
              animate={isActive ? { opacity: 0.5 } : { opacity: 0 }}
              transition={{ duration: 1 }}
              className="absolute inset-0 bg-cover bg-center brightness-[0.7]"
              style={{ y: bgY, backgroundImage: `url(${backgroundImage})` }}
            />
          )}
        </AnimatePresence>
        {id === 'hero' && <TechBackground />}
        <div className="absolute inset-0 z-[3] bg-gradient-to-r from-surface via-surface/30 to-transparent pointer-events-none" />
      </div>

      <div className="relative z-10 px-6 md:px-20 lg:px-32 max-w-7xl w-full mx-auto">
        <motion.div initial={{ opacity: 0, y: 20 }} animate={isActive ? { opacity: 1, y: 0 } : {}}>
          {subtitle && <div className="mb-2">{subtitle}</div>}
          <h1 className="text-4xl md:text-7xl lg:text-8xl font-heading font-extrabold tracking-tight mb-6 text-white leading-none">
            {title}<BrandingSeal />
          </h1>
          {content && <p className="text-base md:text-xl text-white/70 max-w-2xl mb-10 leading-relaxed">{content}</p>}
          {showButton && (
            <motion.button 
              whileHover={{ scale: 1.05, x: 5, backgroundColor: '#2563eb' }}
              className="group bg-primary text-white font-bold py-4 px-10 rounded-xl flex items-center gap-4 transition-colors shadow-2xl shadow-primary/20"
            >
              <span className="text-[10px] uppercase tracking-[0.3em] font-black">{buttonText}</span>
              <ArrowRight size={18} className="group-hover:translate-x-1 transition-transform" />
            </motion.button>
          )}
        </motion.div>
      </div>
    </section>
  );
};

export default Section;

